// اقرأ بيانات الوِبهوك والـ input
const webhookData = $('WhatsApp Webhook').first().json;
const firstItem = $input.first();

const name = webhookData.body?.entry?.[0]?.changes?.[0]?.value?.contacts?.[0]?.profile?.name || "";
const phone = webhookData.body?.entry?.[0]?.changes?.[0]?.value?.contacts?.[0]?.wa_id || firstItem.json.phone || "";

// لو فيه binary جاهز من عقدة سابقة، خذه
const bin = firstItem.binary || {};
const binaryKey = Object.keys(bin)[0] || ""; // مثال: "file" أو "data"
if (!name || !phone || !binaryKey) {
  throw new Error("مطلوب name و phone و ملف binary من العقدة السابقة.");
}

const subject = "إشعار تواصل جديد";
const html = `
<!doctype html>
<html lang="ar" dir="rtl">
<head>
  <meta charset="utf-8"><title>${subject}</title>
  <style>
    body { background:#e8f3ff; direction:rtl; text-align:right; font-family:'Segoe UI',Roboto,Helvetica,Arial,sans-serif; margin:0; padding:0; }
    .container { max-width:600px; margin:24px auto; background:#fff; border-radius:12px; overflow:hidden; box-shadow:0 4px 16px rgba(13,71,161,0.15); }
    .header { background:linear-gradient(135deg,#0D47A1,#00B894); padding:20px; color:#fff; }
    .content { padding:24px; }
    .row { margin:0 0 12px 0; }
    .label { color:#0D47A1; font-weight:600; }
    .footer { background:#f7fafc; padding:16px; font-size:12px; color:#555; border-top:1px solid #e9eef8; }
    .brand { color:#0D47A1; font-weight:600; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h2 style="margin:0;">${subject}</h2>
      <p style="margin:6px 0 0 0;">لقد تم استلام طلب جديد من موقعك</p>
    </div>
    <div class="content">
      <p class="row"><span class="label">الاسم:</span> ${name}</p>
      <p class="row"><span class="label">رقم الهاتف:</span> ${phone}</p>
      <p class="row">المرفق تم إرفاقه مع هذا البريد.</p>
    </div>
    <div class="footer">
      تم الإرسال بواسطة <span class="brand">تواصل العيادات</span>
    </div>
  </div>
</body>
</html>
`;

// رجّع نفس الـ binary حتى يلتقطه Email node كمرفق
return [
  {
    json: { subject, html },
    binary: { [binaryKey]: bin[binaryKey] },
  },
];

const items = $input.all();

// Get phone number from webhook
const phoneNumber = $('WhatsApp Webhook').first().json.body.entry[0].changes[0].value.messages[0].from || '';

// Try to get text from different sources
let textFromWhisper;
let textFromWebhook;
let textFromImage;

// 1. Try to get transcribed voice from Whisper
try {
  textFromWhisper = $('Transcribe Audio').first().json.text;
  console.log('Voice text found:', textFromWhisper);
} catch (e) {
  textFromWhisper = undefined;
}

// 2. Try to get regular text message from webhook
try {
  textFromWebhook = $('WhatsApp Webhook').first().json.body.entry[0].changes[0].value.messages[0].text.body;
  console.log('Text message found:', textFromWebhook);
} catch (e) {
  textFromWebhook = undefined;
}

// 3. Try to get image analysis from Edit Fields node
try {
  textFromImage = $('Edit Fields').first().json.text;
  console.log('Image analysis found:', textFromImage);
} catch (e) {
  textFromImage = undefined;
}

// Combine all available text sources
// Priority: voice > image > text message
let finalText = textFromWhisper || textFromImage || textFromWebhook || '';

// Add source indicator for debugging
let source = '';
if (textFromWhisper) {
  source = 'voice';
} else if (textFromImage) {
  source = 'image';
} else if (textFromWebhook) {
  source = 'text';
}

console.log('Final text source:', source);
console.log('Final text:', finalText);

return items.map(item => {
  return {
    json: {
      phone: phoneNumber,
      text: finalText,
      source: source, // للمعرفة من وين جاي النص
      timestamp: new Date().toISOString()
    }
  };
});

// استخراج البيانات الأساسية
const jsText = $('Prepare Text Data').first().json.text || '';
const phoneNumber = $('Prepare Text Data').first().json.phone || '';
const wa_id = $('WhatsApp Webhook').item.json.body.entry[0].changes[0].value.metadata.phone_number_id;
const name = $('WhatsApp Webhook').first().json.body.entry[0].changes[0].value.contacts[0].profile.name;

// Get available slots
let availableSlots = [];
try {
  const slotsData = $('Get Slots1').all();
  console.log('Get Slots1 data:', JSON.stringify(slotsData.map(s => s.json)));

  availableSlots = slotsData.map(slot => {
    console.log('Slot structure:', Object.keys(slot.json));

    const date = slot.json['التاريخ (A)'] || slot.json.date || slot.json.التاريخ || '';
    const time = slot.json['الوقت (B)'] || slot.json.time || slot.json.الوقت || '';
    const service = slot.json['الخدمة (C)'] || slot.json.service || slot.json.الخدمة || '';

    return `${date} - ${time} (${service})`;
  });

  console.log('Available slots formatted:', availableSlots);
} catch (e) {
  console.error('Error fetching slots:', e.message);
  availableSlots = [];
}

// Get existing appointments for this customer
let existingAppointments = [];
try {
  const appointmentsData = $('Get appointment1').all();
  console.log('Get History1 appointments:', appointmentsData.length);

  existingAppointments = appointmentsData.map(apt => {
    console.log('Appointment structure:', Object.keys(apt.json));

    const date = apt.json.date || '';
    const time = apt.json.times || apt.json.time || '';
    const service = apt.json.service || '';
    const name = apt.json.name || '';

    return `${date} at ${time} - ${service} (${name})`;
  });

  console.log('Existing appointments formatted:', existingAppointments);
} catch (e) {
  console.error('Error fetching existing appointments:', e.message);
  existingAppointments = [];
}

// Format conversation history from Get History1
let formattedHistory = '';
let historyCount = 0;
try {
  const historyData = $('Get History').all().slice(0, 10);
  historyCount = historyData.length;
  console.log('Get History1 data:', historyCount);

  formattedHistory = historyData.map(entry => {
    const createdAt = entry.json.createdAt || '';
    const aiResponse = entry.json.reciever || entry.json.ai || '';
    const userMessage = entry.json.sender || entry.json.user || '';

    // Format timestamp as yyyy-mm-dd:HH:MM
    let formattedTime = '';
    if (createdAt) {
      const date = new Date(createdAt);
      const year = date.getFullYear();
      const month = String(date.getMonth() + 1).padStart(2, '0');
      const day = String(date.getDate()).padStart(2, '0');
      const hours = String(date.getHours()).padStart(2, '0');
      const minutes = String(date.getMinutes()).padStart(2, '0');
      formattedTime = `${year}-${month}-${day}:${hours}:${minutes}`;
    }

    return `( ${formattedTime}, ai: ${aiResponse}, user: ${userMessage})`;
  }).join('\n');

  console.log('Formatted history:', formattedHistory);
} catch (e) {
  console.error('Error formatting history:', e.message);
  formattedHistory = '';
  historyCount = 0;
}

// ⚠️ FIX: Get ALL user appointments and format them
let userAppointments = '';
let userAppointmentsCount = 0;
try {
  const userAppts = $input.all(); // Get ALL appointments
  userAppointmentsCount = userAppts.length;

  if (userAppointmentsCount > 0) {
    userAppointments = userAppts.map((apt, index) => {
      const aptName = apt.json.name || '';
      const aptService = apt.json.service || '';
      const aptDate = apt.json.date ? apt.json.date.split('T')[0] : '';
      const aptDay = apt.json.day || '';
      const aptTime = apt.json.times || '';

      return `
موعد ${index + 1}:
الاسم: ${aptName}
الخدمة: ${aptService}
📅 التاريخ: ${aptDate} | ${aptDay}
🕐 الوقت: ${aptTime}`;
    }).join('\n---\n');
  } else {
    userAppointments = 'لا يوجد مواعيد محجوزة حالياً';
  }

  console.log('User appointments formatted:', userAppointments);
} catch (e) {
  console.error('Error fetching user appointments:', e.message);
  userAppointments = 'لا يوجد مواعيد محجوزة حالياً';
  userAppointmentsCount = 0;
}
let type = $('Prepare Text Data').first().json.source;
let users_id = $('Insert Row Memory').first().json.id;

const result = {
  sender: phoneNumber,
  text: jsText,
  available_slots: availableSlots.join('\n'), 
  available_slots_count: availableSlots.length,
  existing_appointments: existingAppointments.join('\n'),
  existing_appointments_count: existingAppointments.length,
  formatted_output: formattedHistory,
  history_count: historyCount,
  name,
  wa_id,
  users_appointments: userAppointments, // ✅ All appointments formatted
  users_appointments_count: userAppointmentsCount, // ✅ Count of appointments
  users_id,
  type
};

console.log('Final output:', JSON.stringify(result, null, 2));

return [
  {
    json: result
  }
];

