// Parse JSON from AI Data Extractor and add metadata
const raw = $input.first().json.output || '{}';
const phone = $('Format Context').first().json.sender || '';
const name = $('Format Context').first().json.name || '';

let data;

try {
  // Try parsing as-is first
  data = typeof raw === 'object' ? raw : JSON.parse(raw);
} catch (e) {
  // Clean and retry if initial parse fails
  try {
    let cleaned = raw
      .replace(/```json\n?/g, '')
      .replace(/```\n?/g, '')
      .trim();

    // Extract JSON object
    const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
    cleaned = jsonMatch ? jsonMatch[0] : cleaned;

    data = JSON.parse(cleaned);
  } catch (e2) {
    // Fallback to default structure
    console.error('JSON parse failed:', e2.message);
    console.error('Raw input:', raw);

    data = {
      has_appointment: false,
      is_reschedule: false,
      needs_human: false,
      appointment_date: null,
      appointment_day: null,
      appointment_time: null,
      service: null,
      lead_category: 'other',
      description: 'فشل في استخراج البيانات',
      notes: 'خطأ في تحليل الرد'
    };
  }
}

// Enrich with metadata
const enrichedData = {
  ...data,
  phone,
  customer_name: name,
  created_at: new Date().toISOString(),
  has_appointment_text: data.has_appointment ? 'YES' : 'NO',
  is_reschedule_text: data.is_reschedule ? 'YES' : 'NO',
  needs_human_text: data.needs_human ? 'YES' : 'NO'
};

// Replace null/undefined with empty strings
Object.keys(enrichedData).forEach(key => {
  if (enrichedData[key] === null || enrichedData[key] === undefined) {
    enrichedData[key] = '';
  }
});

console.log('Enriched data:', JSON.stringify(enrichedData, null, 2));

return [{ json: enrichedData }];

// Split into two separate message outputs
const input = $input.first().json;
let response = input.output || input.text || input.response || input;

console.log('Raw input:', JSON.stringify(input, null, 2));

try {
  if (typeof response === 'object' && response !== null && (response.summary || response.category)) {
    // Return as single output with both fields
    return {
      json: {
        summary: response.summary || "",
        category: response.category || ""
      }
    };
  }

  if (typeof response === 'string') {
    response = response.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const data = JSON.parse(response);

    return {
      json: {
        summary: data.summary || "",
        category: data.category || ""
      }
    };
  }

  throw new Error('Unexpected response format');

} catch (error) {
  console.error('Parse error:', error.message);
  return {
    json: {
      summary: "Error parsing response",
      category: "error"
    }
  };
}
